#!/usr/bin/env dotnet

Span<nint> nints = stackalloc nint[4];
for (int i = 0; i < nints.Length; i++)
    nints[i] = (nint)(i * 100);

Console.WriteLine($"Span<nint> length: {nints.Length}, sizeof(nint): {sizeof(nint)}");
for (int i = 0; i < nints.Length; i++)
    Console.WriteLine($"  [{i}] = {nints[i]}");

Span<nuint> nuints = stackalloc nuint[3];
for (int i = 0; i < nuints.Length; i++)
    nuints[i] = (nuint)(i * 42);

Console.WriteLine($"Span<nuint> length: {nuints.Length}, sizeof(nuint): {sizeof(nuint)}");
for (int i = 0; i < nuints.Length; i++)
    Console.WriteLine($"  [{i}] = {nuints[i]}");

